public class Trie {
    private TrieNode root = new TrieNode();

    public void insert(String word) {
        TrieNode node = root;
        for (char c : word.toCharArray()) {
            int idx = c - 'a';
            if (node.children[idx] == null)
                node.children[idx] = new TrieNode();
            node = node.children[idx];
        }
        node.isEnd = true;
    }

    public boolean search(String word) {
        TrieNode node = root;
        for (char c : word.toCharArray()) {
            int idx = c - 'a';
            if (node.children[idx] == null) return false;
            node = node.children[idx];
        }
        return node.isEnd;  // must be a complete word
    }

    public boolean startsWith(String prefix) {
        TrieNode node = root;
        for (char c : prefix.toCharArray()) {
            int idx = c - 'a';
            if (node.children[idx] == null) return false;
            node = node.children[idx];
        }
        return true;  // prefix exists (isEnd doesn't matter)
    }
}

class CountTrie {
    int count = 0;           // words passing through this node
    CountTrie[] ch = new CountTrie[26];

    static CountTrie root = new CountTrie();

    static void insert(String word) {
        CountTrie node = root;
        node.count++;
        for (char c : word.toCharArray()) {
            int idx = c - 'a';
            if (node.ch[idx] == null) node.ch[idx] = new CountTrie();
            node = node.ch[idx];
            node.count++;
        }
    }

    // Count words that start with the given prefix
    static int countPrefix(String prefix) {
        CountTrie node = root;
        for (char c : prefix.toCharArray()) {
            int idx = c - 'a';
            if (node.ch[idx] == null) return 0;  // prefix not found
            node = node.ch[idx];
        }
        return node.count;  // count of all words passing through here
    }
}

public class SegmentTree {
    private int[] tree;
    private int n;

    public SegmentTree(int[] nums) {
        n = nums.length;
        tree = new int[4 * n];  // 4n is safe upper bound
        build(nums, 0, 0, n - 1);
    }

    private void build(int[] nums, int node, int start, int end) {
        if (start == end) {
            tree[node] = nums[start];  // leaf
        } else {
            int mid = (start + end) / 2;
            build(nums, 2*node+1, start, mid);
            build(nums, 2*node+2, mid+1, end);
            tree[node] = tree[2*node+1] + tree[2*node+2];  // merge children
        }
    }

    public void update(int idx, int val, int node, int start, int end) {
        if (start == end) { tree[node] = val; return; }
        int mid = (start + end) / 2;
        if (idx <= mid) update(idx, val, 2*node+1, start, mid);
        else            update(idx, val, 2*node+2, mid+1, end);
        tree[node] = tree[2*node+1] + tree[2*node+2];  // recompute
    }

    public int query(int l, int r, int node, int start, int end) {
        if (r < start || end < l) return 0;   // out of range
        if (l <= start && end <= r) return tree[node];  // fully in range
        int mid = (start + end) / 2;
        return query(l, r, 2*node+1, start, mid)
             + query(l, r, 2*node+2, mid+1, end);
    }
}

public class FenwickTree {
    private int[] tree;
    private int n;

    public FenwickTree(int n) {
        this.n = n;
        tree = new int[n + 1];  // 1-indexed
    }

    // Add delta to index i (1-indexed)
    public void update(int i, int delta) {
        for (; i <= n; i += i & (-i))  // i += least significant bit
            tree[i] += delta;
    }

    // Prefix sum from 1 to i
    public int query(int i) {
        int sum = 0;
        for (; i > 0; i -= i & (-i))   // i -= least significant bit
            sum += tree[i];
        return sum;
    }

    // Range sum from l to r
    public int rangeQuery(int l, int r) {
        return query(r) - query(l - 1);
    }
}

public class Solution {
    private Set<String> found = new HashSet<>();
    private int[][] dirs = {{0,1},{0,-1},{1,0},{-1,0}};

    public List<String> findWords(char[][] board, String[] words) {
        // Build trie from all words
        TrieNode root = new TrieNode();
        for (String w : words) insert(root, w);

        int m = board.length, n = board[0].length;
        for (int r = 0; r < m; r++)
            for (int c = 0; c < n; c++)
                dfs(board, r, c, root, new StringBuilder(), m, n);

        return new ArrayList<>(found);
    }

    private void dfs(char[][] board, int r, int c,
                     TrieNode node, StringBuilder path, int m, int n) {
        if (r<0||r>=m||c<0||c>=n||board[r][c]=='#') return;
        char ch = board[r][c];
        TrieNode next = node.children[ch - 'a'];
        if (next == null) return;  // PRUNE: prefix not in trie

        path.append(ch);
        board[r][c] = '#';  // mark visited

        if (next.isEnd) found.add(path.toString());  // found a word!

        for (int[] d : dirs)
            dfs(board, r+d[0], c+d[1], next, path, m, n);

        path.deleteCharAt(path.length()-1);  // backtrack
        board[r][c] = ch;                    // restore
    }
}

