public class Solution {
    static class TrieNode {
        TrieNode[] ch = new TrieNode[26];
        String word; // stores complete word at the end node
    }

    public List<String> findWords(char[][] board, String[] words) {
        TrieNode root = new TrieNode();
        for (String w : words) {
            TrieNode node = root;
            for (char c : w.toCharArray()) {
                int i = c - 'a';
                if (node.ch[i] == null) node.ch[i] = new TrieNode();
                node = node.ch[i];
            }
            node.word = w;
        }

        List<String> result = new ArrayList<>();
        for (int r = 0; r < board.length; r++)
            for (int c = 0; c < board[0].length; c++)
                dfs(board, r, c, root, result);
        return result;
    }

    private void dfs(char[][] board, int r, int c, TrieNode node, List<String> res) {
        if (r < 0 || c < 0 || r >= board.length || c >= board[0].length || board[r][c] == '#') return;
        char ch = board[r][c];
        TrieNode next = node.ch[ch - 'a'];
        if (next == null) return;
        if (next.word != null) { res.add(next.word); next.word = null; } // avoid duplicates
        board[r][c] = '#';
        dfs(board, r+1, c, next, res); dfs(board, r-1, c, next, res);
        dfs(board, r, c+1, next, res); dfs(board, r, c-1, next, res);
        board[r][c] = ch;
    }
}

