public class Solution {
    static class TrieNode {
        TrieNode[] ch = new TrieNode[26];
        boolean isRoot;
    }

    public String replaceWords(List<String> dictionary, String sentence) {
        TrieNode root = new TrieNode();
        // Build trie from dictionary roots
        for (String word : dictionary) {
            TrieNode node = root;
            for (char c : word.toCharArray()) {
                int i = c - 'a';
                if (node.ch[i] == null) node.ch[i] = new TrieNode();
                node = node.ch[i];
            }
            node.isRoot = true;
        }

        StringBuilder sb = new StringBuilder();
        for (String word : sentence.split(" ")) {
            if (sb.length() > 0) sb.append(' ');
            sb.append(findRoot(root, word));
        }
        return sb.toString();
    }

    private String findRoot(TrieNode root, String word) {
        TrieNode node = root;
        StringBuilder sb = new StringBuilder();
        for (char c : word.toCharArray()) {
            int i = c - 'a';
            if (node.ch[i] == null) return word; // no root found
            node = node.ch[i];
            sb.append(c);
            if (node.isRoot) return sb.toString(); // shortest root
        }
        return word;
    }
}

