public class Solution {
    static class TrieNode {
        TrieNode[] ch = new TrieNode[26];
        boolean isEnd;
        String word;
    }

    public String longestWord(String[] words) {
        TrieNode root = new TrieNode();
        // Insert all words
        for (String w : words) {
            TrieNode node = root;
            for (char c : w.toCharArray()) {
                int i = c - 'a';
                if (node.ch[i] == null) node.ch[i] = new TrieNode();
                node = node.ch[i];
            }
            node.isEnd = true;
            node.word = w;
        }

        String result = "";
        // BFS — only traverse through nodes where every prefix is a complete word
        Queue<TrieNode> queue = new LinkedList<>();
        queue.offer(root);
        while (!queue.isEmpty()) {
            TrieNode node = queue.poll();
            for (TrieNode child : node.ch) {
                if (child != null && child.isEnd) {
                    queue.offer(child);
                    String w = child.word;
                    if (w.length() > result.length() ||
                        (w.length() == result.length() && w.compareTo(result) < 0))
                        result = w;
                }
            }
        }
        return result;
    }
}

