class AutocompleteSystem {
    static class TrieNode {
        TrieNode[] ch = new TrieNode[128]; // ASCII to handle spaces
        Map<String, Integer> freq = new HashMap<>();
    }
    private TrieNode root = new TrieNode();
    private TrieNode cur;
    private StringBuilder typed = new StringBuilder();

    public AutocompleteSystem(String[] sentences, int[] times) {
        root = new TrieNode();
        for (int i = 0; i < sentences.length; i++)
            addSentence(sentences[i], times[i]);
        cur = root;
    }

    private void addSentence(String s, int freq) {
        TrieNode node = root;
        for (char c : s.toCharArray()) {
            if (node.ch[c] == null) node.ch[c] = new TrieNode();
            node = node.ch[c];
            node.freq.merge(s, freq, Integer::sum);
        }
    }

    public List<String> input(char c) {
        if (c == '#') {
            String sentence = typed.toString();
            addSentence(sentence, 1);
            typed.setLength(0);
            cur = root;
            return new ArrayList<>();
        }
        typed.append(c);
        if (cur != null) cur = cur.ch[c];
        if (cur == null) return new ArrayList<>();

        // Get top 3: sort by -frequency, then lex
        return cur.freq.entrySet().stream()
            .sorted((a, b) -> a.getValue().equals(b.getValue())
                ? a.getKey().compareTo(b.getKey())
                : b.getValue() - a.getValue())
            .limit(3)
            .map(Map.Entry::getKey)
            .collect(java.util.stream.Collectors.toList());
    }
}

