class RangeMinQuery {
    private int[] tree;
    private int n;

    public RangeMinQuery(int[] nums) {
        n = nums.length;
        tree = new int[4 * n];
        build(nums, 1, 0, n - 1);
    }

    private void build(int[] nums, int node, int l, int r) {
        if (l == r) { tree[node] = nums[l]; return; }
        int mid = (l + r) / 2;
        build(nums, 2*node, l, mid);
        build(nums, 2*node+1, mid+1, r);
        tree[node] = Math.min(tree[2*node], tree[2*node+1]);
    }

    public void update(int i, int val) { update(1, 0, n-1, i, val); }

    private void update(int node, int l, int r, int i, int val) {
        if (l == r) { tree[node] = val; return; }
        int mid = (l + r) / 2;
        if (i <= mid) update(2*node, l, mid, i, val);
        else update(2*node+1, mid+1, r, i, val);
        tree[node] = Math.min(tree[2*node], tree[2*node+1]);
    }

    public int queryMin(int l, int r) { return query(1, 0, n-1, l, r); }

    private int query(int node, int nl, int nr, int l, int r) {
        if (r < nl || nr < l) return Integer.MAX_VALUE;
        if (l <= nl && nr <= r) return tree[node];
        int mid = (nl + nr) / 2;
        return Math.min(query(2*node, nl, mid, l, r),
                        query(2*node+1, mid+1, nr, l, r));
    }
}

