public class Solution {
    static class TrieNode {
        TrieNode[] ch = new TrieNode[26];
        boolean isEnd;
    }

    public int[][] indexPairs(String text, String[] words) {
        TrieNode root = new TrieNode();
        for (String w : words) {
            TrieNode node = root;
            for (char c : w.toCharArray()) {
                int i = c - 'a';
                if (node.ch[i] == null) node.ch[i] = new TrieNode();
                node = node.ch[i];
            }
            node.isEnd = true;
        }

        List<int[]> result = new ArrayList<>();
        int n = text.length();
        for (int i = 0; i < n; i++) {
            TrieNode node = root;
            for (int j = i; j < n; j++) {
                int idx = text.charAt(j) - 'a';
                if (node.ch[idx] == null) break;
                node = node.ch[idx];
                if (node.isEnd) result.add(new int[]{i, j});
            }
        }
        // Result is already sorted by i (outer loop), then j (inner loop)
        return result.toArray(new int[0][]);
    }
}

