public class Solution {
    private int[][] trie = new int[32 * 100000][2];
    private int trieSize = 1;

    private void insert(int num) {
        int node = 0;
        for (int i = 31; i >= 0; i--) {
            int bit = (num >> i) & 1;
            if (trie[node][bit] == 0) trie[node][bit] = trieSize++;
            node = trie[node][bit];
        }
    }

    private int maxXor(int num) {
        int node = 0, xor = 0;
        for (int i = 31; i >= 0; i--) {
            int bit = (num >> i) & 1;
            int want = 1 - bit; // we want the opposite bit
            if (trie[node][want] != 0) { xor |= (1 << i); node = trie[node][want]; }
            else node = trie[node][bit];
        }
        return xor;
    }

    public int findMaximumXOR(int[] nums) {
        for (int num : nums) insert(num);
        int max = 0;
        for (int num : nums) max = Math.max(max, maxXor(num));
        return max;
    }
}

