public class Solution {
    private int lower, upper;

    public int countRangeSum(int[] nums, int lower, int upper) {
        this.lower = lower;
        this.upper = upper;
        long[] prefix = new long[nums.length + 1];
        for (int i = 0; i < nums.length; i++) prefix[i+1] = prefix[i] + nums[i];
        return mergeCount(prefix, 0, prefix.length - 1);
    }

    private int mergeCount(long[] prefix, int l, int r) {
        if (l >= r) return 0;
        int mid = (l + r) / 2;
        int count = mergeCount(prefix, l, mid) + mergeCount(prefix, mid+1, r);

        // Count valid pairs: left half = prefix[i], right half = prefix[j], j > i
        int lo = l, hi = l;
        for (int j = mid + 1; j <= r; j++) {
            while (lo <= mid && prefix[j] - prefix[lo] > upper) lo++;
            while (hi <= mid && prefix[j] - prefix[hi] >= lower) hi++;
            count += hi - lo;
        }

        // Standard merge sort step
        long[] sorted = new long[r - l + 1];
        int i = l, j = mid + 1, k = 0;
        while (i <= mid && j <= r)
            sorted[k++] = prefix[i] <= prefix[j] ? prefix[i++] : prefix[j++];
        while (i <= mid) sorted[k++] = prefix[i++];
        while (j <= r)   sorted[k++] = prefix[j++];
        System.arraycopy(sorted, 0, prefix, l, sorted.length);
        return count;
    }
}
